              "ui_proxy_server.py",
              "brain_server /v1/agent/status"
            ],
            "outputs": [
              "Panel Blocked muestra step_id/proposal_id/required_approve cuando existe",
              "Blocked: — cuando no existe"
            ],
            "done_criteria": [
              "Cuando status.blocked existe, se ven botones Apply/Reject.",
              "Al click Apply: POST /ui/api/apply devuelve ok=true y en <=2s el panel pasa a Blocked: — (porque blocked se consumió).",
