            ],
            "tests": [
              "Smoke UI: crear plan con append_file; run -> blocked; apply desde UI -> archivo cambia; status -> blocked=null.",
              "Negativo: si no hay blocked, Apply/Reject no hace nada y lo loggea."
            ]
          }
        ]
      },
      {
        "phase": "P2_PLANNER_HARDENING_SCHEMA_NORMALIZATION",
        "objective": "Hacer que el planner (Ollama→Plan) sea determinístico respecto al schema y normalice content/newlines.",
        "status": "next",
        "work_items": [
          {
            "id": "P2.1",
            "title": "Garantizar tool_args.content no-null y string",
            "description": "Antes de persistir plan, validar/corregir steps: tool_args.content debe ser string; si planner da null, generar fallback desde prompt (p.ej. 'hola <now_iso>\
').",
            "implementation_notes": [
              "Validación server-side en POST /v1/agent/plan: normalizar pasos antes de write plan.json.",
              "Si content contiene '\\\
' literal (dos chars), convertir a newline real cuando el tool sea write/append.",
              "Mantener original en audit para trazabilidad: store both raw_content and normalized_content (opcional)."
            ],
            "done_criteria": [
              "No se observan tool_args.content = null en plan.json final.",
              "append_file/write_file siempre reciben content con newlines reales cuando se solicita 'newline at end'."
            ],
            "tests": [
              "Casos: 'hola 2026-03-03T01:56:58Z' -> content reemplazado y termina en '\
' real.",
              "Casos: prompt en español e inglés; planner no debe emitir expresiones tipo '\"hola \" + ...' que rompan JSON."
            ]
          },
          {
            "id": "P2.2",
            "title": "Normalización 'now_iso' consistente",
            "description": "Definir una única fuente: UI puede interpolar nowIso() antes de /plan, o el server puede interpolar al ejecutar. Elegir una y eliminar ambigüedad.",
            "decision": "Preferir interpolación en UI antes de POST /plan para transparencia; server mantiene fallback si detecta placeholder '2026-03-03T01:56:58Z'.",
            "done_criteria": [
              "En plan.json persistido, content ya contiene timestamp ISO (sin placeholders), salvo que se configure allow_placeholders=true.",
              "Ejecución produce líneas con newline real."
            ]
          }
        ]
      },
      {
        "phase": "P3_PLANNER_EXECUTOR_EVALUATOR_LOOP",
        "objective": "Implementar loop canónico Planner → Executor → Evaluator con SSOT, políticas y evidencia; con supervisión.",
        "status": "planned",
        "work_items": [
          {
            "id": "P3.1",
            "title": "Estructurar episode.json por run",
            "description": "Cada run crea/actualiza episode.json por room+run_id con inputs, plan snapshot, tool_calls, outputs, violations, y links a artifacts.",
            "done_criteria": [
              "episode.json siempre existe para run; incluye tool_calls[] con timestamps y resultados.",
              "episode.json referencia plan.json (hash/mtime) y proposal ids aplicadas/rechazadas."
            ]
          },
          {
            "id": "P3.2",
            "title": "Evaluator determinístico (U-score)",
            "description": "Implementar compute_u(metrics, violations) determinístico con pesos versionados (u_model_version) y outputs action=continue|replan|halt.",
            "done_criteria": [
              "Para el mismo episode, evaluate retorna el mismo u_score (a tolerancia fija).",
              "violations reducen U de forma monotónica.",
              "action rules documentadas (thresholds) y testeadas."
            ]
          },
          {
            "id": "P3.3",
            "title": "policy_registry y promoción degradación",
            "description": "policy_registry.json acumula políticas/SOPs con evidencia; se promueven solo tras revisión humana o thresholds conservadores.",
            "done_criteria": [
              "policy_registry contiene entries con: id, description, scope, evidence_refs, status, created_at, last_seen_at.",
              "policy_events.ndjson registra cada cambio de status."
            ]
          },
          {
            "id": "P3.4",
            "title": "run loop supervisado",
            "description": "Autonomía incremental: run puede ejecutar múltiples steps, pero todo write pasa por proposals; el sistema se detiene en blocked o halt.",
            "done_criteria": [
              "Si aparece blocked, run se detiene y UI muestra Apply/Reject; al resolver, se reanuda.",
              "Stop conditions: max_steps, repeated_no_progress, safety_violation, user_halt."
            ]
          }
        ]
      },
      {
        "phase": "P4_SELF_CONSTRUCTION_PIPELINE_SUPERVISED",
        "objective": "Permitir que el agente 'se autoconstruya' (mejoras de código/config) bajo gates, con pruebas y rollback.",
        "status": "planned",
        "work_items": [
          {
            "id": "P4.1",
            "title": "Proposal bundling + apply gate robusto",
            "description": "Toda modificación de archivos fuente se empaqueta como proposal (diff + rationale + tests). Apply ejecuta: backup -> patch -> py_compile -> smoke -> commit snapshot; si falla, rollback.",
            "done_criteria": [
              "Cada apply deja snapshot PRE y POST con hashes.",
              "Si post-smoke falla en strict, rollback automático deja sistema como antes.",
              "En warn, se registra pero no rollback (configurable)."
            ]
          },
          {
            "id": "P4.2",
            "title": "Test harness local",
            "description": "Scripts canónicos: py_compile, smoke UI, smoke agent run/apply, y regresión básica.",
            "done_criteria": [
              "Un solo comando PS corre el set mínimo de pruebas y produce reporte."
            ]
          },
          {
            "id": "P4.3",
            "title": "Governance: permisos por tool y por path",
            "description": "Policy engine decide qué tools pueden usarse según objetivo y riesgo; cambios a whitelist requieren aprobación humana.",
            "done_criteria": [
              "Intentos de usar tool no autorizada quedan bloqueados y auditados.",
              "Cambios a allowed_roots requieren proposal."
            ]
          }
        ]
      },
      {
        "phase": "P5_RAG_SOPS_EPISODIC_LEARNING",
        "objective": "Aprendizaje incremental: RAG sobre vault + SOPs versionados + dataset de episodios para mejoras futuras.",
        "status": "planned",
        "work_items": [
          {
            "id": "P5.1",
            "title": "Indexación básica (RAG local)",
            "description": "Indexar docs/ops/runs y knowledge base en vectores; responder preguntas con citas internas (file+offset).",
            "done_criteria": [
              "Consulta '¿qué hicimos ayer?' devuelve resumen con referencias a audit/episode.",
              "No usa web por defecto; solo vault."
            ]
          },
          {
            "id": "P5.2",
            "title": "SOPs + selección por rendimiento",
            "description": "SOPs describen procedimientos (e.g., 'patch seguro'); se puntúan por U-score y se recomiendan/activan.",
            "done_criteria": [
              "SOP tiene id, triggers, steps, risks, tests, and evidence; evaluator los puntúa."
            ]
          }
        ]
      },
      {
        "phase": "P6_AUTONOMY_GROWTH_WITH_SUPERVISION",
        "objective": "Cerrar el loop para objetivos largos: planificación jerárquica, ejecución incremental, evaluación periódica, y supervisión.",
        "status": "planned",
        "work_items": [
          {
            "id": "P6.1",
            "title": "Orquestación de objetivos (goal stack)",
            "description": "goal.json por room con objetivos, subobjetivos, estado y prioridades; plan.json referencia goal_id.",
            "done_criteria": [
              "GET /v1/agent/goal y POST /goal gestionan stack.",
              "Evaluator puede proponer replan o descomposición."
            ]
          },
          {
            "id": "P6.2",
            "title": "Autonomía condicionada",
            "description": "Modo autónomo: corre ciclos cada N minutos/trigger, pero solo avanza si no requiere aprobación o si hay aprobaciones pendientes.",
            "done_criteria": [
              "Scheduler local (task) dispara run/evaluate; se detiene si blocked>0.",
              "Checkpoints envían resumen y requieren confirmación humana según policy."
            ]
          }
        ]
      }
    ],
    "runbooks": {
      "ui_happy_path": [
        "1) Selecciona/define room_id (ej: room_ui_write_smoke_X).",
        "2) Escribe instrucción en natural language (o JSON) y presiona Chat→Plan→Run.",
        "3) Si aparece Blocked: revisa step_id/proposal_id y presiona Apply o Reject.",
        "4) Presiona Refresh All para ver Status/Mission/Plan actualizados.",
        "5) Verifica artifact (archivo) y/o plan.json en SSOT."
      ],
      "debug_if_blocked_disappears": [
        "A) Si blocked desaparece tras Apply: es correcto; significa que proposal fue consumida.",
        "B) Confirma ejecución revisando: /v1/agent/status (blocked=null) y el archivo/resultado del step.",
        "C) Si el archivo no cambió: revisar plan.json (tool_args.content) y audit.ndjson para ver bytes escritos."
      ]
    }
  }
}

